import React, { useState } from 'react';
import { ShoppingBag, Truck, Store, CreditCard, AlertTriangle, Trash2, Plus, Minus } from 'lucide-react';

const Carrito = ({ cart, setCart, onCheckout }) => {
  const [modoEntrega, setModoEntrega] = useState('delivery');
  const [paso, setPaso] = useState('revision');

  // CÁLCULO DE PESO EXACTO: Usamos Number para asegurar que los decimales se sumen correctamente
  const totalPeso = cart.reduce((acc, p) => acc + (Number(p.peso) || 0), 0);
  const totalPrecio = cart.reduce((acc, p) => acc + (Number(p.precioNuevo) || 0), 0);

  const ajustarCantidad = (producto, accion) => {
    if (accion === 'sumar') {
      const unidadesEnCarrito = cart.filter(item => item.id === producto.id).length;
      if (unidadesEnCarrito >= producto.stock) {
        return alert(`Límite de stock: solo hay ${producto.stock} disponibles.`);
      }
      setCart([...cart, { ...producto, instanceId: Date.now() + Math.random() }]);
    } else {
      const index = cart.findLastIndex(item => item.id === producto.id);
      if (index > -1) {
        const nuevoCarrito = [...cart];
        nuevoCarrito.splice(index, 1);
        setCart(nuevoCarrito);
      }
    }
  };

  const eliminarProductoCompleto = (id) => {
    setCart(cart.filter(item => item.id !== id));
  };

  // Agrupamos los productos para mostrar la cantidad x producto
  const itemsAgrupados = cart.reduce((acc, item) => {
    if (!acc[item.id]) {
      acc[item.id] = { ...item, cantidad: 0 };
    }
    acc[item.id].cantidad += 1;
    return acc;
  }, {});

  return (
    <div style={cartContainer}>
      <div style={headerCart}>
        <h3 style={title}><ShoppingBag size={20} color="#e67e22" /> Tu Pedido</h3>
        <span style={itemCount}>{cart.length} ítems</span>
      </div>
      
      <div style={deliverySelector}>
        <button onClick={() => setModoEntrega('delivery')} style={modoEntrega === 'delivery' ? btnActive : btnInactive}>
          <Truck size={16} /> Delivery
        </button>
        <button onClick={() => setModoEntrega('retiro')} style={modoEntrega === 'retiro' ? btnActive : btnInactive}>
          <Store size={16} /> Retiro
        </button>
      </div>

      {modoEntrega === 'delivery' && (
        <div style={totalPeso > 15 ? errorBox : weightBox}>
          <AlertTriangle size={14} /> 
          <span>Peso: <strong>{totalPeso.toFixed(3)} kg</strong> / 15kg</span>
        </div>
      )}

      {paso === 'revision' ? (
        <>
          <div style={listStyle}>
            {Object.values(itemsAgrupados).map((item) => (
              <div key={item.id} style={itemRow}>
                <div style={{ flex: 1 }}>
                  <div style={itemName}>{item.producto}</div>
                  <div style={itemSubtext}>{item.peso}kg | ${(item.precioNuevo * item.cantidad).toLocaleString()}</div>
                </div>
                
                <div style={qtyControls}>
                  <button style={btnQty} onClick={() => ajustarCantidad(item, 'restar')}><Minus size={12} /></button>
                  <span style={qtyNum}>{item.cantidad}</span>
                  <button style={btnQty} onClick={() => ajustarCantidad(item, 'sumar')}><Plus size={12} /></button>
                </div>

                <button style={btnTrash} onClick={() => eliminarProductoCompleto(item.id)}>
                  <Trash2 size={16} color="#ef4444" />
                </button>
              </div>
            ))}
          </div>
          
          <div style={totalBox}>
            <div style={totalRow}>
              <span>Total</span>
              <span>${totalPrecio.toLocaleString()}</span>
            </div>
          </div>
          
          <button 
            disabled={modoEntrega === 'delivery' && totalPeso > 15}
            onClick={() => setPaso('pago')} 
            style={totalPeso > 15 && modoEntrega === 'delivery' ? btnDisabled : btnPrimario}
          >
            Continuar al Pago
          </button>
        </>
      ) : (
        <div style={formPago}>
          <p style={{fontSize: '0.9rem', marginBottom: '15px'}}>Simulación de Pago Online</p>
          <button onClick={onCheckout} style={btnPrimario}>Finalizar Pago de ${totalPrecio}</button>
          <button onClick={() => setPaso('revision')} style={btnVolver}>Volver a revisión</button>
        </div>
      )}
    </div>
  );
};

// --- ESTILOS (DEFINIDOS TODOS AQUÍ PARA EVITAR EL ERROR) ---
const cartContainer = { background: 'white', padding: '20px', borderRadius: '20px', boxShadow: '0 10px 25px rgba(0,0,0,0.1)', width: '350px', position: 'sticky', top: '90px' };
const headerCart = { display: 'flex', justifyContent: 'space-between', marginBottom: '15px' };
const title = { display: 'flex', alignItems: 'center', gap: '8px', margin: 0, fontSize: '1.1rem' };
const itemCount = { fontSize: '0.8rem', background: '#f1f5f9', padding: '2px 8px', borderRadius: '10px' };
const deliverySelector = { display: 'flex', gap: '8px', marginBottom: '15px', background: '#f8fafc', padding: '4px', borderRadius: '12px' };
const btnActive = { flex: 1, padding: '8px', border: 'none', borderRadius: '8px', background: '#1e293b', color: 'white', fontWeight: 'bold', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '5px' };
const btnInactive = { flex: 1, padding: '8px', border: 'none', background: 'transparent', color: '#64748b', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '5px' };
const weightBox = { background: '#f0fdf4', color: '#166534', padding: '10px', borderRadius: '10px', fontSize: '0.8rem', display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '15px' };
const errorBox = { ...weightBox, background: '#fef2f2', color: '#991b1b', border: '1px solid #fecaca' };
const listStyle = { borderTop: '1px solid #f1f5f9', paddingTop: '10px' };
const itemRow = { display: 'flex', alignItems: 'center', padding: '12px 0', borderBottom: '1px solid #f1f5f9' };
const itemName = { fontWeight: '600', color: '#1e293b', fontSize: '0.9rem' };
const itemSubtext = { fontSize: '0.75rem', color: '#94a3b8' };
const qtyControls = { display: 'flex', alignItems: 'center', background: '#f8fafc', borderRadius: '8px', padding: '4px', margin: '0 10px' };
const btnQty = { border: 'none', background: 'white', borderRadius: '4px', cursor: 'pointer', display: 'flex', alignItems: 'center', padding: '2px' };
const qtyNum = { margin: '0 8px', fontSize: '0.85rem', fontWeight: 'bold' };
const btnTrash = { background: 'none', border: 'none', cursor: 'pointer', padding: '5px' };
const totalBox = { margin: '20px 0' };
const totalRow = { display: 'flex', justifyContent: 'space-between', fontWeight: 'bold', fontSize: '1.2rem', color: '#e67e22' };
const btnPrimario = { width: '100%', padding: '14px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer' };
const btnDisabled = { ...btnPrimario, background: '#cbd5e1', cursor: 'not-allowed' };
const btnVolver = { width: '100%', background: 'none', border: 'none', marginTop: '10px', color: '#64748b', cursor: 'pointer', fontSize: '0.8rem' };
const formPago = { textAlign: 'center', paddingTop: '20px' };

export default Carrito;
